var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-4 ","JPN":"<color=#ffd34c>プリドウェン機関</color>の秘密隔離施設 LAKE-4 ","ENG":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","TWN":"<color=#ffd34c>普利多溫機關</color>秘密隔離設施LAKE-4","SCN":"<color=#ffd34c>普利多温机关</color>秘密隔离设施LAKE-4","DEU":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","FRA":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 <color=#ffd34c>최고등급 재난경보</color> 발령 후 3시간 뒤","JPN":"管理局<color=#ffd34c>最高ランクの災難警報</color>発令から3時間後","ENG":"3 hours after the Administration issuing the <color=#ffd34c>highest-level disaster alert</color>","TWN":"管理局發佈<color=#ffd34c>最高級災難警報</color>3小時後","SCN":"管理局发布<color=#ffd34c>最高级灾难警报</color>3小时后","DEU":"3 hours after the Administration issuing the <color=#ffd34c>highest-level disaster alert</color>","FRA":"3 hours after the Administration issuing the <color=#ffd34c>highest-level disaster alert</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"제길, 이곳의 수복이 아직 완전히 끝나지도 않았는데, 최고등급 재난 경보라니…….","JPN":"くそ、ここの修復がまだ完全に終わってないのに、最高ランクの災難警報とは……","ENG":"Bollocks, we haven't even fully recovered this area, and now a highest-level disaster alert...?","TWN":"可惡，這裡的收復工作還沒完全結束，就發佈了最高級別的災難警報……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"그야말로 설상가상이로군.","JPN":"弱り目に祟り目ってまさにこれだな。","ENG":"It's only gotten worse.","TWN":"真是雪上加霜。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"전 인원, 복구 작업을 중단하고 모두 레벨 3 이상의 CSE 방호복을 착용해!","JPN":"総員、復旧作業を中断してみんなレベル3以上のCSE防護服を着用しろ！","ENG":"All units are to stop the restoration work and put on protective suits of CSE levels 3 and higher!","TWN":"全體人員，停止收復工作，全部穿上3級以上CSE防護服！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"시설에 봉인된 파편이 눈보라에 노출되지 않도록 방재 작업을 최우선으로 수행한다!","JPN":"施設に封印された破片が吹雪に晒されないよう、防災作業を最優先に遂行する！","ENG":"Prioritise disaster prevention, so that the Fragment sealed within the facility aren't exposed to the snowstorm!","TWN":"優先做好防災工作，確保封印在設施的碎片不會暴露在暴風雪下！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"프레임에 고정된 봉인 사슬을 보호해! 방수포라도 덮어 놔!","JPN":"フレームに固定された封印の鎖を保護しろ！　防水布でも被せておけ！","ENG":"Protect the Sealing Chains fixed to the frame! Cover it with a waterproof tarp or something!","TWN":"保護固定在邊框上的封印鎖鏈！把防水布蓋上！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"지휘관님! 학회 녀석들이 시설을 습격했습니다!","JPN":"指揮官！　学会のやつらが施設を襲撃しました！","ENG":"Commander! The Society bastards are attacking the facility!","TWN":"指揮官！學會的傢伙正在襲擊設施！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 뭐라고!?","JPN":"な、何だと！？","ENG":"W-what?!","TWN":"什，什麼？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"이곳뿐만이 아닙니다. 다른 봉인 시설에서도 동시에 보고가 들어왔습니다!","JPN":"ここだけではありません。他の封印施設からも同様の報告が来ています！","ENG":"Not just this one. We've received simultaneous reports from the other quarantine facilities as well!","TWN":"不光是這裡，其他封印設施也同時發來了遇襲報告！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"녀석들을 막아!","JPN":"やつらを止めろ！","ENG":"Stop them!","TWN":"攔住他們！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 학회에서도 버려진 떨거지들일 뿐이다!","JPN":"どうせ学会からも見捨てられた落ちこぼれだ！","ENG":"They're nothing but failures that were abandoned by the Society!","TWN":"他們只是被學會拋棄的嘍囉而已！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"중대장님! 이터니움 실드의 소모량이 너무 빠릅니다!","JPN":"中隊長！　エタニウムシールドの消耗が激しいです！","ENG":"Sir! The Eternium shield is rapidly decaying!","TWN":"中隊長！永恆之金盾的消耗太快了！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"습격한 적들의 편성은 대다수가 애콜라이트와 잔해입니다.","JPN":"襲撃した敵の編成は、ほとんどがアコライトと残骸です。","ENG":"The enemies consist mostly of Acolytes and Remains.","TWN":"襲擊的敵人大多數是輔祭和殘骸。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"고위 침식파장에도 끄떡없어요!","JPN":"高レベルの侵食波長にもビクともしません！","ENG":"The high-grade Corruption ray isn't doing anything to them!","TWN":"連高級侵蝕波也拿他們沒辦法！"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"이대로 가다간…… 싸우기도 전에 다들 미쳐버릴 겁니다!","JPN":"このままでは……戦う前にみんなおかしくなってしまいます！","ENG":"At this rate... we're all going to be driven mad before we even get a chance to fight!","TWN":"照這樣下去……還沒打起來，大家就會瘋掉！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"제길! D-7 구역까지 후퇴한 뒤, 그곳에서 이터니움을 충전하고 방어전을 전개한다.","JPN":"くそ！　D-7区域まで撤退し、そこでエタニウムを充電して防御戦を展開する。","ENG":"Bloody hell! We retreat to area D-7, charge Eternium, and switch to defensive combat.","TWN":"該死！撤退到D-7區域後，在那裡補充永恆之金，然後展開防禦戰。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳을 두 번 잃을 수는 없어!","JPN":"二度もここを失うわけにはいかない！","ENG":"We can't lose this place again!","TWN":"這個地方不能再丟第二次了！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장님의 명령이 있을 때까지 무슨 일이 있어도 버텨야 한다!","JPN":"機関長の命令があるまで、何があって耐えしのげ！","ENG":"We cannot fall before we receive any orders from the Chief!","TWN":"不管發生什麼事，都要堅持到機關長下達命令！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"기관 녀석들이 물러나고 있다! 서둘러!","JPN":"機関のやつらが押されているぞ！　急げ！","ENG":"The Institution pricks are falling back! Hurry!","TWN":"機關的傢伙們正在撤退！快點！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이곳을 점령하고 파편을 회수한다!","JPN":"ここを占領して破片を回収する！","ENG":"Capture the area and retrieve the Fragment!","TWN":"我們要佔領這裡，回收碎片！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"모든 것은 지식의 호수가 하나가 되기 위해서!","JPN":"すべては、知識の湖が一つになるため！","ENG":"For the Lake of Knowledge to become one!","TWN":"一切都是為了讓知識湖水合而為一！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"L48_1","ENG":"L48_1","TWN":"L48_1","SCN":"L48_1","DEU":"L48_1","FRA":"L48_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};